```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null, string? searchTerm = null)
    {
        var query = db.Shipments.AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<Data.ShipmentStatus>(statusFilter, true, out var status))
        {
            query = query.Where(s => s.Status == status);
        }

        if (!string.IsNullOrEmpty(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(s =>
                s.TrackingNumber.ToLower().Contains(term) ||
                s.Destination.ToLower().Contains(term) ||
                s.RecipientName.ToLower().Contains(term) ||
                s.Origin.ToLower().Contains(term));
        }

        return await query.OrderByDescending(s => s.LastUpdated)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = $"SHP-{Guid.NewGuid().ToString("N")[..8].ToUpper()}",
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = Data.ShipmentStatus.Pending,
            EstimatedDelivery = dto.EstimatedDelivery,
            RecipientName = dto.RecipientName,
            Description = dto.Description,
            CreatedAt = DateTime.UtcNow,
            LastUpdated = DateTime.UtcNow
        };
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    public async Task<ShipmentDto> UpdateShipmentAsync(ShipmentDto dto)
    {
        var shipment = await db.Shipments.FindAsync(dto.Id)
            ?? throw new InvalidOperationException("Shipment not found");
        shipment.Origin = dto.Origin;
        shipment.Destination = dto.Destination;
        shipment.Status = (Data.ShipmentStatus)(int)dto.Status;
        shipment.EstimatedDelivery = dto.EstimatedDelivery;
        shipment.RecipientName = dto.RecipientName;
        shipment.Description = dto.Description;
        shipment.LastUpdated = DateTime.UtcNow;
        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (Client.Models.ShipmentStatus)(int)s.Status,
        EstimatedDelivery = s.EstimatedDelivery,
        RecipientName = s.RecipientName,
        Description = s.Description,
        CreatedAt = s.CreatedAt,
        LastUpdated = s.LastUpdated
    };
}
