    private string formError = string.Empty;
    private ShipmentDto formModel = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetShipmentsAsync(statusFilter, searchTerm);
        loading = false;
    }

    private async Task ClearFilters()
    {
        searchTerm = string.Empty;
        statusFilter = string.Empty;
        await LoadShipments();
    }

    private void ShowCreateForm()
    {
        formModel = new ShipmentDto { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
        isEditing = false;
        formError = string.Empty;
        showForm = true;
    }

    private void EditShipment(ShipmentDto shipment)
    {
        formModel = new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            RecipientName = shipment.RecipientName,
            Description = shipment.Description,
            Status = shipment.Status,
            EstimatedDelivery = shipment.EstimatedDelivery
        };
        isEditing = true;
        formError = string.Empty;
        showForm = true;
    }

    private void CloseForm()
    {
        showForm = false;
    }

    private async Task SaveShipment()
    {
        if (string.IsNullOrWhiteSpace(formModel.Origin) ||
            string.IsNullOrWhiteSpace(formModel.Destination) ||
            string.IsNullOrWhiteSpace(formModel.RecipientName))
        {
            formError = "Origin, Destination, and Recipient Name are required.";
            return;
        }

        saving = true;
        formError = string.Empty;
        try
        {
            if (isEditing)
                await ShipmentService.UpdateShipmentAsync(formModel);
            else
                await ShipmentService.CreateShipmentAsync(formModel);

            showForm = false;
            await LoadShipments();
        }
        catch (Exception ex)
        {
            formError = $"Error saving shipment: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
