@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services

<PageTitle>Track Shipment - @TrackingNumber</PageTitle>

<div class="container">
    <h2 class="mb-4">Shipment Tracking</h2>

    @if (loading)
    {
        <div class="d-flex justify-content-center my-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (shipment is null)
    {
        <div class="alert alert-warning">
            <h5 class="alert-heading">Shipment Not Found</h5>
            <p>No shipment was found with tracking number <strong>@TrackingNumber</strong>.</p>
            <hr />
            <a href="/" class="btn btn-outline-primary">Try Another Number</a>
        </div>
    }
    else
    {
        <div class="card shadow-sm mb-4">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">@shipment.TrackingNumber</h5>
                <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <dl>
                            <dt>Origin</dt>
                            <dd>@shipment.Origin</dd>
                            <dt>Destination</dt>
                            <dd>@shipment.Destination</dd>
                            <dt>Recipient</dt>
                            <dd>@shipment.RecipientName</dd>
                        </dl>
                    </div>
                    <div class="col-md-6">
                        <dl>
                            <dt>Description</dt>
                            <dd>@(string.IsNullOrEmpty(shipment.Description) ? "—" : shipment.Description)</dd>
                            <dt>Estimated Delivery</dt>
                            <dd>@shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</dd>
                            <dt>Last Updated</dt>
                            <dd>@shipment.LastUpdated.ToString("g")</dd>
                        </dl>
                    </div>
                </div>

                <!-- Progress bar -->
                <div class="mt-3">
                    <h6>Shipment Progress</h6>
                    <div class="progress" style="height: 30px;">
                        <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                             role="progressbar"
                             style="width: @GetProgressPercent(shipment.Status)%"
                             aria-valuenow="@GetProgressPercent(shipment.Status)"
                             aria-valuemin="0" aria-valuemax="100">
                            @shipment.Status
                        </div>
                    </div>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2">
            <a href="/" class="btn btn-outline-secondary">Track Another</a>
            <button class="btn btn-outline-primary" @onclick="Refresh">Refresh</button>
        </div>
    }
</div>

@code {
    [Parameter] public string TrackingNumber { get; set; } = string.Empty;
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private ShipmentDto? shipment;
    private bool loading = true;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipment();
    }

    private async Task LoadShipment()
    {
        loading = true;
        shipment = await ShipmentService.GetByTrackingNumberAsync(TrackingNumber);
        loading = false;
    }

    private async Task Refresh() => await LoadShipment();

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}

