+@page "/shipments"
+@using Microsoft.AspNetCore.Authorization
+@using ShipmentTracker.Client.Models
+@using ShipmentTracker.Client.Services
+@attribute [Authorize]
+
+<PageTitle>Shipments - Dispatcher View</PageTitle>
+
+<div class="container-fluid">
+    <div class="d-flex justify-content-between align-items-center mb-4">
+        <h2>Shipments</h2>
+        <button class="btn btn-primary" @onclick="ShowCreateForm">
+            + New Shipment
+        </button>
+    </div>
+
+    <!-- Filters -->
+    <div class="row mb-3 g-2">
+        <div class="col-md-4">
+            <input type="text" class="form-control" placeholder="Search by tracking #, destination, recipient..."
+                   @bind="searchTerm" @bind:event="oninput" @bind:after="LoadShipments" />
+        </div>
+        <div class="col-md-3">
+            <select class="form-select" @bind="statusFilter" @bind:after="LoadShipments">
+                <option value="">All Statuses</option>
+                @foreach (var status in Enum.GetValues<ShipmentStatus>())
+                {
+                    <option value="@status">@status</option>
+                }
+            </select>
+        </div>
+        <div class="col-md-2">
+            <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
+        </div>
+    </div>
+
+    @if (loading)
+    {
+        <div class="d-flex justify-content-center my-5">
+            <div class="spinner-border text-primary" role="status">
+                <span class="visually-hidden">Loading...</span>
+            </div>
+        </div>
+    }
+    else
+    {
+        <div class="table-responsive">
+            <table class="table table-striped table-hover">
+                <thead class="table-dark">
+                    <tr>
+                        <th>Tracking #</th>
+                        <th>Origin</th>
+                        <th>Destination</th>
+                        <th>Recipient</th>
+                        <th>Status</th>
+                        <th>Est. Delivery</th>
+                        <th>Actions</th>
+                    </tr>
+                </thead>
+                <tbody>
+                    @if (shipments.Count == 0)
+                    {
+                        <tr>
+                            <td colspan="7" class="text-center text-muted py-4">No shipments found.</td>
+                        </tr>
+                    }
+                    @foreach (var s in shipments)
+                    {
+                        <tr>
+                            <td><a href="/track/@s.TrackingNumber">@s.TrackingNumber</a></td>
+                            <td>@s.Origin</td>
+                            <td>@s.Destination</td>
+                            <td>@s.RecipientName</td>
+                            <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
+                            <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
+                            <td>
+                                <button class="btn btn-sm btn-outline-primary" @onclick="() => EditShipment(s)">Edit</button>
+                            </td>
+                        </tr>
+                    }
+                </tbody>
+            </table>
+        </div>
+    }
+
+    @if (showForm)
+    {
+        <div class="modal d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5);">
+            <div class="modal-dialog">
+                <div class="modal-content">
+                    <div class="modal-header">
+                        <h5 class="modal-title">@(isEditing ? "Edit Shipment" : "New Shipment")</h5>
+                        <button type="button" class="btn-close" @onclick="CloseForm"></button>
+                    </div>
+                    <div class="modal-body">
+                        @if (!string.IsNullOrEmpty(formError))
+                        {
+                            <div class="alert alert-danger">@formError</div>
+                        }
+                        <div class="mb-3">
+                            <label class="form-label">Origin</label>
+                            <input type="text" class="form-control" @bind="formModel.Origin" />
+                        </div>
+                        <div class="mb-3">
+                            <label class="form-label">Destination</label>
+                            <input type="text" class="form-control" @bind="formModel.Destination" />
+                        </div>
+                        <div class="mb-3">
+                            <label class="form-label">Recipient Name</label>
+                            <input type="text" class="form-control" @bind="formModel.RecipientName" />
+                        </div>
+                        <div class="mb-3">
+                            <label class="form-label">Description</label>
+                            <input type="text" class="form-control" @bind="formModel.Description" />
+                        </div>
+                        <div class="mb-3">
+                            <label class="form-label">Estimated Delivery</label>
+                            <input type="date" class="form-control" @bind="formModel.EstimatedDelivery" />
+                        </div>
+                        @if (isEditing)
+                        {
+                            <div class="mb-3">
+                                <label class="form-label">Status</label>
+                                <select class="form-select" @bind="formModel.Status">
+                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
+                                    {
+                                        <option value="@status">@status</option>
+                                    }
+                                </select>
+                            </div>
+                        }
+                    </div>
+                    <div class="modal-footer">
+                        <button type="button" class="btn btn-secondary" @onclick="CloseForm">Cancel</button>
+                        <button type="button" class="btn btn-primary" @onclick="SaveShipment" disabled="@saving">
+                            @(saving ? "Saving..." : "Save")
+                        </button>
+                    </div>
+                </div>
+            </div>
+        </div>
+    }
+</div>
+
+@code {
+    [Inject] private IShipmentService ShipmentService { get; set; } = default!;
+
+    private List<ShipmentDto> shipments = [];
+    private bool loading = true;
+    private string searchTerm = string.Empty;
+    private string statusFilter = string.Empty;
+
+    private bool showForm;
+    private bool isEditing;
+    private bool saving;
+    private string formError = string.Empty;
+    private ShipmentDto formModel = new();
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadShipments();
+    }
+
+    private async Task LoadShipments()
+    {
+        loading = true;
+        shipments = await ShipmentService.GetShipmentsAsync(statusFilter, searchTerm);
+        loading = false;
+    }
+
+    private async Task ClearFilters()
+    {
+        searchTerm = string.Empty;
+        statusFilter = string.Empty;
+        await LoadShipments();
+    }
+
+    private void ShowCreateForm()
+    {
+        formModel = new ShipmentDto { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
+        isEditing = false;
+        formError = string.Empty;
+        showForm = true;
+    }
+
+    private void EditShipment(ShipmentDto shipment)
+    {
+        formModel = new ShipmentDto
+        {
+            Id = shipment.Id,
+            TrackingNumber = shipment.TrackingNumber,
+            Origin = shipment.Origin,
+            Destination = shipment.Destination,
+            RecipientName = shipment.RecipientName,
+            Description = shipment.Description,
+            Status = shipment.Status,
+            EstimatedDelivery = shipment.EstimatedDelivery
+        };
+        isEditing = true;
+        formError = string.Empty;
+        showForm = true;
+    }
+
+    private void CloseForm()
+    {
+        showForm = false;
+    }
+
+    private async Task SaveShipment()
+    {
+        if (string.IsNullOrWhiteSpace(formModel.Origin) ||
+            string.IsNullOrWhiteSpace(formModel.Destination) ||
+            string.IsNullOrWhiteSpace(formModel.RecipientName))
+        {
+            formError = "Origin, Destination, and Recipient Name are required.";
+            return;
+        }
+
+        saving = true;
+        formError = string.Empty;
+        try
+        {
+            if (isEditing)
+                await ShipmentService.UpdateShipmentAsync(formModel);
+            else
+                await ShipmentService.CreateShipmentAsync(formModel);
+
+            showForm = false;
+            await LoadShipments();
+        }
+        catch (Exception ex)
+        {
+            formError = $"Error saving shipment: {ex.Message}";
+        }
+        finally
+        {
+            saving = false;
+        }
+    }
+
+    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Pending => "bg-secondary",
+        ShipmentStatus.PickedUp => "bg-info",
+        ShipmentStatus.InTransit => "bg-primary",
+        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
+        ShipmentStatus.Delivered => "bg-success",
+        ShipmentStatus.Cancelled => "bg-danger",
+        _ => "bg-secondary"
+    };
+}
+

