145. @code {
146.     [Inject] private IShipmentService ShipmentService { get; set; } = default!;
147. 
148.     private List<ShipmentDto> shipments = [];
149.     private bool loading = true;
150.     private string searchTerm = string.Empty;
151.     private string statusFilter = string.Empty;
152. 
153.     private bool showForm;
154.     private bool isEditing;
155.     private bool saving;
156.     private string formError = string.Empty;
157.     private ShipmentDto formModel = new();
158. 
159.     protected override async Task OnInitializedAsync()
160.     {
161.         await LoadShipments();
162.     }
163. 
164.     private async Task LoadShipments()
165.     {
166.         loading = true;
167.         shipments = await ShipmentService.GetShipmentsAsync(statusFilter, searchTerm);
168.         loading = false;
169.     }
170. 
171.     private async Task ClearFilters()
172.     {
173.         searchTerm = string.Empty;
174.         statusFilter = string.Empty;
175.         await LoadShipments();
176.     }
177. 
178.     private void ShowCreateForm()
179.     {
180.         formModel = new ShipmentDto { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
181.         isEditing = false;
182.         formError = string.Empty;
183.         showForm = true;
184.     }
185. 
186.     private void EditShipment(ShipmentDto shipment)
187.     {
188.         formModel = new ShipmentDto
189.         {
190.             Id = shipment.Id,
191.             TrackingNumber = shipment.TrackingNumber,
192.             Origin = shipment.Origin,
193.             Destination = shipment.Destination,
194.             RecipientName = shipment.RecipientName,
195.             Description = shipment.Description,
196.             Status = shipment.Status,
197.             EstimatedDelivery = shipment.EstimatedDelivery
198.         };
199.         isEditing = true;
200.         formError = string.Empty;
201.         showForm = true;
202.     }
203. 
204.     private void CloseForm()
205.     {
206.         showForm = false;
207.     }
208. 
209.     private async Task SaveShipment()
210.     {
211.         if (string.IsNullOrWhiteSpace(formModel.Origin) ||
212.             string.IsNullOrWhiteSpace(formModel.Destination) ||
213.             string.IsNullOrWhiteSpace(formModel.RecipientName))
214.         {
215.             formError = "Origin, Destination, and Recipient Name are required.";
216.             return;
217.         }
218. 
219.         saving = true;
220.         formError = string.Empty;
221.         try
222.         {
223.             if (isEditing)
224.                 await ShipmentService.UpdateShipmentAsync(formModel);
225.             else
226.                 await ShipmentService.CreateShipmentAsync(formModel);
227. 
228.             showForm = false;
229.             await LoadShipments();
230.         }
231.         catch (Exception ex)
232.         {
233.             formError = $"Error saving shipment: {ex.Message}";
234.         }
235.         finally
236.         {
237.             saving = false;
238.         }
239.     }
240. 
241.     private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
242.     {
243.         ShipmentStatus.Pending => "bg-secondary",
244.         ShipmentStatus.PickedUp => "bg-info",
245.         ShipmentStatus.InTransit => "bg-primary",
246.         ShipmentStatus.OutForDelivery => "bg-warning text-dark",
247.         ShipmentStatus.Delivered => "bg-success",
248.         ShipmentStatus.Cancelled => "bg-danger",
249.         _ => "bg-secondary"
250.     };
251. }
252.

